{
  "learning_outcomes": [
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–1: Electric Charges and Fields",
      "topic": "Electrostatics - Charges, Fields, and Flux",
      "outcomes": [
        "Apply the principle of superposition and conservation of charge in systems with multiple point charges.",
        "Calculate electric field intensity due to point charges, continuous distributions, and dipoles (axial/equatorial).",
        "Determine torque on an electric dipole placed in a uniform electric field.",
        "Apply Gauss's theorem to calculate fields for infinite wires, plane sheets, and spherical shells."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–2: Electrostatic Potential and Capacitance",
      "topic": "Electrostatic Potential - Energy, Capacitance, and Dielectrics",
      "outcomes": [
        "Calculate electric potential and potential difference due to point charges, dipoles, and charge systems.",
        "Identify properties of conductors, insulators, free/bound charges, and dielectrics (polarization).",
        "Analyze capacitors in series/parallel combinations and calculate capacitance with/without dielectric media.",
        "Determine energy stored in a capacitor using standard formulae."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Chapter–3: Current Electricity",
      "topic": "Current Electricity - Circuits, Ohm's Law, and Networks",
      "outcomes": [
        "Relate electric current to drift velocity and mobility of charge carriers in conductors.",
        "Analyze V-I characteristics (linear/non-linear) and temperature dependence of resistance/resistivity/conductivity.",
        "Apply Kirchhoff's rules to solve complex circuit networks including Wheatstone bridge configurations.",
        "Calculate equivalent EMF, internal resistance, and terminal potential difference for cells in series/parallel."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–4: Moving Charges and Magnetism",
      "topic": "Magnetic Effects - Fields, Forces, and Instruments",
      "outcomes": [
        "Apply Biot-Savart law for circular loops and Ampere's law for straight wires/solenoids (qualitative).",
        "Calculate force on moving charges in combined electric/magnetic fields and current-carrying conductors.",
        "Analyze torque on a current loop, defining magnetic dipole moment and its relation to galvanometer sensitivity.",
        "Design conversions of galvanometers into ammeters or voltmeters."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–5: Magnetism and Matter",
      "topic": "Magnetism - Materials, Dipoles, and Properties",
      "outcomes": [
        "Model a bar magnet as an equivalent solenoid qualitatively.",
        "Calculate torque on a magnetic dipole in a uniform field and describe magnetic field lines.",
        "Classify substances based on magnetic properties (para-, dia-, ferro-) with examples."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–6: Electromagnetic Induction",
      "topic": "Electromagnetic Induction - Laws and Applications",
      "outcomes": [
        "State and apply Faraday's laws of electromagnetic induction to calculate induced EMF."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–7: Alternating Current",
      "topic": "Alternating Current - AC Circuits, Power, and Transformers",
      "outcomes": [
        "Distinguish between peak and RMS values of alternating current/voltage."
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Chapter–8: Electromagnetic Waves",
      "topic": "Electromagnetic Waves - Spectrum and Properties",
      "outcomes": [
        "Explain the concept of displacement current leading to the existence of EM waves."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–9: Ray Optics and Optical Instruments",
      "topic": "Ray Optics - Reflection, Refraction, and Instruments",
      "outcomes": [
        "Apply the mirror formula and lens maker's formula for spherical mirrors and thin lenses."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–10: Wave Optics",
      "topic": "Wave Optics - Interference, Diffraction, and Huygens' Principle",
      "outcomes": [
        "Apply Huygen's principle to derive laws of reflection and refraction."
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Chapter–11: Dual Nature of Radiation and Matter",
      "topic": "Dual Nature - Photoelectric Effect and Matter Waves",
      "outcomes": [
        "Explain the experimental observations (Hertz/Lenard) leading to Einstein's photoelectric equation."
      ]
    },
    {
      "unit_name": "Unit–VIII Atoms and Nuclei",
      "chapter_name": "Chapter–12: Atoms",
      "topic": "Atoms - Rutherford, Bohr Models, and Spectra",
      "outcomes": [
        "Describe the alpha-particle scattering experiment leading to Rutherford's nuclear model."
      ]
    },
    {
      "unit_name": "Unit–VIII Atoms and Nuclei",
      "chapter_name": "Chapter–13: Nuclei",
      "topic": "Nuclei - Structure, Binding Energy, Fission/Fusion",
      "outcomes": [
        "Explain the concept of mass defect and its relation to binding energy per nucleon."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Chapter–14: Semiconductor Electronics: Materials, Devices and Simple Circuits",
      "topic": "Electronic Devices - Semiconductors, Diodes, and Rectification",
      "outcomes": [
        "Differentiate between conductors, insulators, and semiconductors based on energy band theory."
      ]
    }
  ]
}
